@namespace Lumeo

@{
    var context = new SplitterContext(
        _groupId,
        Orientation,
        _children,
        RegisterChild,
        UnregisterChild,
        ResizeNeighbors
    );
}

<div id="@_groupId"
     class="@CssClass"
     style="min-width:0;min-height:0;"
     data-splitter-orientation="@OrientationString"
     @attributes="AdditionalAttributes">
    <CascadingValue Value="context" IsFixed="false">
        @ChildContent
    </CascadingValue>
</div>

@inject IComponentInteropService Interop

@code {
    [Parameter] public Lumeo.Orientation Orientation { get; set; } = Lumeo.Orientation.Horizontal;
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly string _groupId = LumeoIds.New("splitter");
    private readonly List<object> _children = new();

    private string OrientationString => Orientation == Lumeo.Orientation.Horizontal ? "horizontal" : "vertical";

    private string CssClass =>
        Orientation == Lumeo.Orientation.Horizontal
            ? Cx.Merge("flex flex-row h-full w-full", Class)
            : Cx.Merge("flex flex-col h-full w-full", Class);

    private void RegisterChild(object child)
    {
        if (!_children.Contains(child))
            _children.Add(child);
    }

    private void UnregisterChild(object child)
    {
        _children.Remove(child);
    }

    private IEnumerable<SplitterPaneHandle> Panes =>
        _children.OfType<SplitterPaneHandle>();

    protected override void OnAfterRender(bool firstRender)
    {
        // Re-run distribution whenever there are still-unsized panes — not only
        // on the first render. A pane added AFTER the initial layout (a tab
        // opened, a conditional @if flipping true) registers with Size 0 and was
        // previously left invisible because the one-shot _distributed guard had
        // already latched. Now any unsized pane triggers a fresh share-out (#258).
        DistributeInitialSizes();
    }

    private void DistributeInitialSizes()
    {
        var panes = Panes.ToList();
        if (panes.Count == 0) return;

        var unsetPanes = panes.Where(p => p.Size <= 0 && !p.Collapsed).ToList();
        if (unsetPanes.Count == 0) return;

        // Space already claimed by sized (or collapsed) panes; newcomers split
        // whatever is left so they become visible.
        var usedSpace = panes.Where(p => p.Size > 0 || p.Collapsed).Sum(p => p.Size);
        var remaining = 100 - usedSpace;

        if (remaining > 0.01)
        {
            var share = remaining / unsetPanes.Count;
            foreach (var pane in unsetPanes)
                pane.Size = share;
        }
        else
        {
            // No leftover room — the track is already full (e.g. a third pane
            // added after the initial 50/50 layout). Do NOT equalize every pane:
            // that would wipe the user's deliberate split (#258 follow-up). Give
            // each newcomer a default share and proportionally shrink the
            // already-sized panes so their RELATIVE proportions survive. Assigning
            // a positive size to the newcomer is also what breaks the
            // OnAfterRender→StateHasChanged loop: leaving a pane at 0 keeps it
            // "unset", so the guard above never trips and the re-render recurses
            // until the stack overflows.
            var newcomerShare = 100.0 / panes.Count;
            var totalNewcomerShare = newcomerShare * unsetPanes.Count;

            // Panes that already carry a runtime size (exclude collapsed panes:
            // their fixed CollapsedSize must be preserved, not scaled).
            var sized = panes.Where(p => p.Size > 0 && !p.Collapsed).ToList();
            var sizedSum = sized.Sum(p => p.Size);

            if (sizedSum > 0 && totalNewcomerShare < 100)
            {
                var scale = (100 - totalNewcomerShare) / sizedSum;
                foreach (var pane in sized)
                    pane.Size *= scale;

                foreach (var pane in unsetPanes)
                    pane.Size = newcomerShare;
            }
            else
            {
                // Degenerate fallback (no sized panes to shrink, or newcomers
                // alone would exceed the track): split everything evenly so the
                // newcomer still gets a positive size.
                var active = panes.Where(p => !p.Collapsed).ToList();
                var equal = 100.0 / active.Count;
                foreach (var pane in active)
                    pane.Size = equal;
            }
        }

        StateHasChanged();
    }

    internal async Task ResizeNeighbors(object dividerToken, double deltaPixels)
    {
        // Resolve the two adjacent panes from the LIVE DOM order (triage #195): a
        // keyed @key reorder MOVES reused pane/divider instances to new DOM
        // positions WITHOUT firing OnParametersSet, so the C# mount-order _children
        // list goes stale and a divider would resize the WRONG neighbours. We probe
        // the document-order ids, reproject _children onto them, then walk out from
        // the divider to the nearest pane on each side — so reordering panes moves
        // the right neighbours and divider Arrow/Home/End nav (which routes through
        // here) follows the DOM too. Falls back to the registration order when the
        // probe is unavailable (prerender / JS off / unconfigured test double), so
        // existing un-reordered behaviour is byte-for-byte unchanged.
        var children = await OrderedChildren();
        var idx = children.IndexOf(dividerToken);
        if (idx < 0) return;

        SplitterPaneHandle? before = null;
        for (var i = idx - 1; i >= 0; i--)
        {
            if (children[i] is SplitterPaneHandle p) { before = p; break; }
        }

        SplitterPaneHandle? after = null;
        for (var i = idx + 1; i < children.Count; i++)
        {
            if (children[i] is SplitterPaneHandle p) { after = p; break; }
        }

        if (before is null || after is null) return;

        var dimension = Orientation == Lumeo.Orientation.Horizontal ? "width" : "height";
        var totalSize = await Interop.GetElementDimension(_groupId, dimension);
        if (totalSize <= 0) return;

        var deltaPercent = (deltaPixels / totalSize) * 100.0;
        var pairTotal = before.Size + after.Size;

        // CLAMP rather than reject (#258): a fast drag whose accumulated delta
        // overshoots a boundary lands exactly ON the boundary instead of
        // stalling short. The leading pane's range must also respect BOTH
        // neighbours — it can't grow past where the trailing pane would fall
        // below its MinSize, nor shrink past where the trailing pane would
        // exceed its MaxSize.
        var minBefore = Math.Max(before.MinSize, pairTotal - after.MaxSize);
        var maxBefore = Math.Min(before.MaxSize, pairTotal - after.MinSize);

        var desiredBefore = before.Size + deltaPercent;

        // Collapsible panes: dragging a pane below half its MinSize snaps it to
        // CollapsedSize (default 0) and hands the freed space to its neighbour,
        // instead of clamping at MinSize. Dragging back out past the threshold
        // restores it. Mirrors Radix's collapse-on-drag behaviour.
        // An already-collapsed pane expands on a drag back OUT. Per-pointer-move
        // deltas are small, so accumulate them toward MinSize rather than letting
        // the collapse branch below immediately re-snap to CollapsedSize (which
        // otherwise left a collapsed pane stuck unless a single move crossed the
        // threshold).
        if (before.Collapsible && before.Collapsed && deltaPercent > 0)
        {
            var expanded = Math.Min(before.MinSize, before.Size + deltaPercent);
            before.Size = expanded;
            after.Size = pairTotal - expanded;
            if (before.Size >= before.MinSize) before.Collapsed = false;
            StateHasChanged();
            return;
        }
        if (after.Collapsible && after.Collapsed && deltaPercent < 0)
        {
            var expanded = Math.Min(after.MinSize, after.Size - deltaPercent);
            after.Size = expanded;
            before.Size = pairTotal - expanded;
            if (after.Size >= after.MinSize) after.Collapsed = false;
            StateHasChanged();
            return;
        }
        if (before.Collapsible && !before.Collapsed && desiredBefore < before.MinSize - (before.MinSize - before.CollapsedSize) / 2)
        {
            before.Collapsed = true;
            before.Size = before.CollapsedSize;
            after.Size = pairTotal - before.CollapsedSize;
            StateHasChanged();
            return;
        }
        if (after.Collapsible && !after.Collapsed && (pairTotal - desiredBefore) < after.MinSize - (after.MinSize - after.CollapsedSize) / 2)
        {
            after.Collapsed = true;
            after.Size = after.CollapsedSize;
            before.Size = pairTotal - after.CollapsedSize;
            StateHasChanged();
            return;
        }

        if (minBefore > maxBefore) return; // unsatisfiable constraints

        var newBefore = Math.Clamp(desiredBefore, minBefore, maxBefore);
        before.Size = newBefore;
        after.Size = pairTotal - newBefore;
        // Any resize that lands a pane back at/above its MinSize clears collapse.
        if (before.Size >= before.MinSize) before.Collapsed = false;
        if (after.Size >= after.MinSize) after.Collapsed = false;

        StateHasChanged();
    }

    // _children reprojected onto live DOM order. The probe returns the pane +
    // divider element ids in document order; we map each registry entry by its
    // stable element id and reorder to match, appending any registry entries the
    // probe didn't surface (e.g. not-yet-rendered). An empty / NULL probe result →
    // the registration order verbatim, so existing behaviour is unaffected.
    private async Task<List<object>> OrderedChildren()
    {
        var registry = _children;
        // NOTE: a Loose-mode JSInterop (the bUnit default, and the real service in
        // tests) returns NULL for an unconfigured string[] invocation — null-guard
        // it, don't assume []. The selector matches BOTH panes and dividers so the
        // divider can locate ITSELF in the DOM order and pick its true neighbours.
        string[]? domOrder;
        try
        {
            domOrder = await Interop.GetOrderedDescendantIds(
                _groupId, "[data-splitter-pane],[data-splitter-divider]");
        }
        catch (JSDisconnectedException) { domOrder = null; }
        catch (ObjectDisposedException) { domOrder = null; }
        catch (InvalidOperationException) { domOrder = null; } // JS unavailable (prerender)

        if (domOrder is not { Length: > 0 }) return registry;

        var byId = new Dictionary<string, object>(registry.Count);
        foreach (var child in registry)
        {
            var id = ChildId(child);
            if (!string.IsNullOrEmpty(id)) byId[id!] = child;
        }
        var ordered = new List<object>(registry.Count);
        foreach (var id in domOrder)
            if (byId.Remove(id, out var child)) ordered.Add(child);
        ordered.AddRange(byId.Values);
        return ordered;
    }

    private static string? ChildId(object child) => child switch
    {
        SplitterPaneHandle p => p.Id,
        SplitterDividerToken d => d.Id,
        _ => null
    };

    public class SplitterPaneHandle
    {
        /// <summary>The pane element's id — the addressable anchor the DOM-order
        /// neighbour probe (<see cref="OrderedChildren"/>) maps this handle back to.</summary>
        public string Id { get; set; } = "";
        public double Size { get; set; }
        public double MinSize { get; set; } = 10;
        public double MaxSize { get; set; } = 90;

        /// <summary>When true, the pane snaps to <see cref="CollapsedSize"/> when
        /// dragged below (roughly) half its MinSize, and restores on drag-out.</summary>
        public bool Collapsible { get; set; }

        /// <summary>Percentage the pane occupies while collapsed (default 0).</summary>
        public double CollapsedSize { get; set; }

        /// <summary>Live collapsed state — toggled by drag and the public API.</summary>
        public bool Collapsed { get; set; }
    }

    public class SplitterDividerToken
    {
        /// <summary>The divider element's id — lets the DOM-order probe locate the
        /// divider among its panes so <see cref="ResizeNeighbors"/> picks the live
        /// neighbours after a keyed reorder.</summary>
        public string Id { get; set; } = "";
    }

    public record SplitterContext(
        string GroupId,
        Lumeo.Orientation Orientation,
        List<object> Children,
        Action<object> RegisterChild,
        Action<object> UnregisterChild,
        Func<object, double, Task> ResizeNeighbors
    );
}

@namespace Lumeo
@implements IAsyncDisposable

<div id="@_dividerId"
     role="separator"
     data-splitter-divider
     aria-orientation="@(IsHorizontal ? "vertical" : "horizontal")"
     aria-valuenow="@LeadingPaneValue"
     aria-valuemin="@LeadingPaneMin"
     aria-valuemax="@LeadingPaneMax"
     tabindex="0"
     class="@CssClass"
     @onpointerdown="OnPointerDown"
     @onpointerdown:preventDefault="true"
     @onpointermove="OnPointerMove"
     @onpointerup="OnPointerUp"
     @onpointercancel="OnPointerUp"
     @onkeydown="OnKeyDown"
     @attributes="AdditionalAttributes">
</div>

@inject IComponentInteropService Interop
@inject ThemeService Theme

@code {
    [CascadingParameter] public Splitter.SplitterContext Context { get; set; } = default!;

    // A scoped <DirectionProvider> cascades its direction here; when present it
    // wins over the global ThemeService so a subtree can be RTL even if the app
    // is LTR (and vice versa). Null when no provider wraps this divider — then
    // the ambient theme direction applies.
    [CascadingParameter(Name = "LumeoDirection")] private LayoutDirection? ScopedDirection { get; set; }
    private LayoutDirection EffectiveDirection => ScopedDirection ?? Theme.CurrentDirection;

    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly string _dividerId = LumeoIds.New("splitter-divider");
    private readonly Splitter.SplitterDividerToken _token = new();
    private bool _dragging;
    private long _pointerId;
    private double _lastX;
    private double _lastY;

    private bool IsHorizontal => Context?.Orientation == Lumeo.Orientation.Horizontal;

    // aria-valuenow/min/max describe the LEADING pane's percentage size — the
    // pane just before this divider in the Context.Children list. This matches
    // how ResizeNeighbors mutates `before.Size` on drag/keypress, so the value
    // an assistive tech reads tracks the same number the user is steering.
    //
    // The reported min/max must account for BOTH neighbours, not just the
    // leading pane's own constraints: ResizeNeighbors rejects a move when
    // either neighbour would violate its limits, so a 20/55/25 layout caps
    // the first divider at 65% (trailing pane must stay ≥10%), not the
    // leading pane's own MaxSize of 90.
    private (Splitter.SplitterPaneHandle? leading, Splitter.SplitterPaneHandle? trailing) Neighbours
    {
        get
        {
            if (Context is null) return (null, null);
            var idx = Context.Children.IndexOf(_token);
            if (idx < 0) return (null, null);
            Splitter.SplitterPaneHandle? lead = null, trail = null;
            for (var i = idx - 1; i >= 0; i--)
                if (Context.Children[i] is Splitter.SplitterPaneHandle p) { lead = p; break; }
            for (var i = idx + 1; i < Context.Children.Count; i++)
                if (Context.Children[i] is Splitter.SplitterPaneHandle p) { trail = p; break; }
            return (lead, trail);
        }
    }

    private int LeadingPaneValue => (int)Math.Round(Neighbours.leading?.Size ?? 0);

    private int LeadingPaneMin
    {
        get
        {
            var (l, t) = Neighbours;
            if (l is null) return 0;
            var ownMin = l.MinSize;
            if (t is null) return (int)Math.Round(ownMin);
            // Leading can't shrink past the point where trailing would exceed its MaxSize.
            var pairMin = (l.Size + t.Size) - t.MaxSize;
            return (int)Math.Round(Math.Max(ownMin, pairMin));
        }
    }

    private int LeadingPaneMax
    {
        get
        {
            var (l, t) = Neighbours;
            if (l is null) return 100;
            var ownMax = l.MaxSize;
            if (t is null) return (int)Math.Round(ownMax);
            // Leading can't grow past the point where trailing would drop below its MinSize.
            var pairMax = (l.Size + t.Size) - t.MinSize;
            return (int)Math.Round(Math.Min(ownMax, pairMax));
        }
    }

    private string CssClass =>
        IsHorizontal
            ? Cx.Merge("shrink-0 w-1 self-stretch bg-border hover:bg-primary/50 transition-colors cursor-col-resize touch-none select-none focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-ring", Class)
            : Cx.Merge("shrink-0 h-1 w-full bg-border hover:bg-primary/50 transition-colors cursor-row-resize touch-none select-none focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-ring", Class);

    protected override void OnInitialized()
    {
        // Expose this divider's element id on its registry token so the group's
        // DOM-order neighbour probe can locate the divider among its panes.
        _token.Id = _dividerId;
        Context?.RegisterChild(_token);
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (!firstRender) return;
        try
        {
            // Suppress page scroll for the resize keys ONLY. The previous
            // blanket @onkeydown:preventDefault="true" also cancelled Tab on
            // a tabindex="0" element — a WCAG 2.1.2 keyboard trap: focus
            // could never leave the divider via keyboard.
            // #194 — Home/End/PageUp/PageDown also scroll the page, so they join
            // the arrows in the preventDefault set (Tab is still left untouched).
            var keys = IsHorizontal
                ? new[] { "ArrowLeft", "ArrowRight", "Home", "End", "PageUp", "PageDown" }
                : new[] { "ArrowUp", "ArrowDown", "Home", "End", "PageUp", "PageDown" };
            await Interop.RegisterPreventDefaultKeys(
                _dividerId,
                keys.Select(k => new PreventDefaultKeyRule(k)).ToArray());
            _pdRegistered = true;
        }
        catch (JSDisconnectedException) { }
        catch (ObjectDisposedException) { }
        catch (InvalidOperationException) { } // JS interop unavailable during prerender
    }

    private bool _pdRegistered;

    private async Task OnPointerDown(Microsoft.AspNetCore.Components.Web.PointerEventArgs e)
    {
        _dragging = true;
        _pointerId = e.PointerId;
        _lastX = e.ClientX;
        _lastY = e.ClientY;
        await Interop.SetPointerCaptureOnElement(_dividerId, _pointerId);
    }

    private async Task OnPointerMove(Microsoft.AspNetCore.Components.Web.PointerEventArgs e)
    {
        if (!_dragging) return;
        if (Context is null) return;

        var delta = IsHorizontal ? e.ClientX - _lastX : e.ClientY - _lastY;
        _lastX = e.ClientX;
        _lastY = e.ClientY;

        if (Math.Abs(delta) < 0.001) return;

        await Context.ResizeNeighbors(_token, delta);
    }

    private async Task OnPointerUp(Microsoft.AspNetCore.Components.Web.PointerEventArgs e)
    {
        if (!_dragging) return;
        _dragging = false;
        await Interop.ReleasePointerCaptureOnElement(_dividerId, _pointerId);
    }

    // Keyboard resize: arrow keys move the divider by a fixed 10px step,
    // matching the same Context.ResizeNeighbors path used by pointer drag.
    // Page scroll for the arrow keys is suppressed via the key-selective JS
    // preventDefault registration in OnAfterRenderAsync (Tab must pass).
    // In RTL, ArrowLeft/Right are swapped for horizontal splitters so the key
    // that points toward the visual "start" always shrinks the leading panel.
    //
    // #194 — WAI-ARIA window-splitter completeness: a separator must also honour
    // Home/End (jump to the min/max bound) and PageUp/PageDown (a coarser step
    // than the arrows). These reuse the exact same Context.ResizeNeighbors path
    // and its built-in clamp, so they never touch pane registration or the
    // distribution logic — Home/End simply request a delta large enough that the
    // clamp lands the leading pane on its bound, and PageUp/PageDown request the
    // larger step. The directional flip mirrors the Arrow keys: in a horizontal
    // RTL splitter the key pointing toward the visual "start" shrinks the
    // leading pane, so PageUp/PageDown and Home/End swap sign the same way.
    private async Task OnKeyDown(KeyboardEventArgs e)
    {
        if (Context is null) return;
        const double step = 10.0;
        const double pageStep = step * 10.0; // PageUp/PageDown: 10× the arrow step.
        // A delta far larger than any track so the ResizeNeighbors clamp pins the
        // leading pane exactly on its (neighbour-aware) min/max bound for Home/End.
        const double toBound = 1_000_000.0;

        var isRtl = IsHorizontal && EffectiveDirection == LayoutDirection.Rtl;

        // "shrink" = move the leading pane toward its minimum; "grow" = toward its
        // maximum. In horizontal LTR a negative pixel delta shrinks the leading
        // pane; RTL flips that. Vertical is always top-to-bottom (no flip).
        var shrinkSign = isRtl ? 1.0 : -1.0;
        var growSign = -shrinkSign;

        var delta = (IsHorizontal, e.Key) switch
        {
            (true,  "ArrowLeft")  => isRtl ?  step : -step,
            (true,  "ArrowRight") => isRtl ? -step :  step,
            (false, "ArrowUp")    => -step,
            (false, "ArrowDown")  =>  step,

            // PageUp moves toward the start (shrink leading), PageDown toward the
            // end (grow leading) — same convention as ArrowUp/ArrowLeft etc., but
            // a coarser step. The clamp in ResizeNeighbors keeps it in bounds.
            (true,  "PageUp")     => shrinkSign * pageStep,
            (true,  "PageDown")   => growSign   * pageStep,
            (false, "PageUp")     => -pageStep,
            (false, "PageDown")   =>  pageStep,

            // Home collapses the leading pane to its min bound; End expands it to
            // its max bound. The oversized delta is clamped to land exactly there.
            (true,  "Home")       => shrinkSign * toBound,
            (true,  "End")        => growSign   * toBound,
            (false, "Home")       => -toBound,
            (false, "End")        =>  toBound,

            _ => 0.0
        };

        if (delta != 0.0)
        {
            await Context.ResizeNeighbors(_token, delta);
        }
    }

    public async ValueTask DisposeAsync()
    {
        Context?.UnregisterChild(_token);
        if (!_pdRegistered) return;
        try
        {
            await Interop.UnregisterPreventDefaultKeys(_dividerId);
        }
        catch (JSDisconnectedException) { }
        catch (ObjectDisposedException) { }
        catch (InvalidOperationException) { }
    }
}

@namespace Lumeo
@implements IDisposable

<div id="@_paneId"
     data-splitter-pane
     class="@CssClass"
     style="@InlineStyle"
     @attributes="AdditionalAttributes">
    @ChildContent
</div>

@code {
    [CascadingParameter] public Splitter.SplitterContext Context { get; set; } = default!;
    [Parameter] public double Size { get; set; }
    [Parameter] public double MinSize { get; set; } = 10;
    [Parameter] public double MaxSize { get; set; } = 90;

    /// <summary>
    /// When true, the pane can collapse to <see cref="CollapsedSize"/> by
    /// dragging its divider below (roughly) half the pane's MinSize, and
    /// restores when dragged back out. Previously this flag was inert (#258).
    /// </summary>
    [Parameter] public bool Collapsible { get; set; }

    /// <summary>Percentage size the pane shrinks to when collapsed. Default 0
    /// (fully hidden). Only meaningful when <see cref="Collapsible"/> is true.</summary>
    [Parameter] public double CollapsedSize { get; set; }

    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    // A stable, addressable pane id rendered on the wrapper (with data-splitter-pane)
    // so the group's DOM-order neighbour probe can map this pane back to its Handle
    // after a keyed reorder.
    private readonly string _paneId = LumeoIds.New("splitter-pane");

    internal Splitter.SplitterPaneHandle Handle { get; } = new();

    private string CssClass => Cx.Merge("overflow-hidden", Class);

    private string InlineStyle
    {
        get
        {
            // Use flex-grow ratios instead of flex-basis% so vertical splitters work without requiring
            // an explicit parent height (% basis resolves to auto when parent height is min-height only).
            var size = Handle.Size.ToString("F4", System.Globalization.CultureInfo.InvariantCulture);
            return $"flex: {size} 1 0; min-width: 0; min-height: 0;";
        }
    }

    protected override void OnInitialized()
    {
        Handle.Id = _paneId;
        Handle.Size = Size;
        Handle.MinSize = MinSize;
        Handle.MaxSize = MaxSize;
        Handle.Collapsible = Collapsible;
        Handle.CollapsedSize = CollapsedSize;
        Context?.RegisterChild(Handle);
    }

    protected override void OnParametersSet()
    {
        // Track min/max + collapse config but don't overwrite runtime-computed size
        Handle.MinSize = MinSize;
        Handle.MaxSize = MaxSize;
        Handle.Collapsible = Collapsible;
        Handle.CollapsedSize = CollapsedSize;
    }

    public void Dispose()
    {
        Context?.UnregisterChild(Handle);
    }
}
